// Enhanced security class for sensitive operations
class SecurePaymentHandler {
    private val secureRandom = SecureRandom()
    
    fun generateSecureToken(): String {
        val bytes = ByteArray(32)
        secureRandom.nextBytes(bytes)
        return bytes.joinToString("") { "%02x".format(it) }
    }
    
    fun validatePaymentAmount(amount: Double): Boolean {
        return amount > 0 && amount <= 999999.99
    }
    
    fun sanitizeInput(input: String): String {
        return input.filter { it.isLetterOrDigit() || it.isWhitespace() || it in listOf('.', ',', '-', '_') }
    }
    
    fun maskCardNumber(cardNumber: String): String {
        return cardNumber.takeLast(4).padStart(cardNumber.length, '*')
    }
}